SELECT t.*, s.sales_name AS assignee_sales_name_join
FROM jst_sales_followup_task t
LEFT JOIN jst_sales s ON t.assignee_sales_id = s.sales_id

    AND t.assignee_sales_id = #{assigneeSalesId}
    AND t.channel_id = #{channelId}
    AND t.status = #{status}

ORDER BY t.due_date ASC

